{

}

Code:
public boolean xyBalance(String str) {
    int counter = 0;

    for(int i = 0; i < str.length(); i++){
        if(str.charAt(i) == 'x') counter++;
        if(str.charAt(i) == 'y') counter--;
        if(counter < 0) return false;
    }
    return counter == 0;
}

