Code:
public int sum13(int[] nums) {
    int sum = 0;
    boolean skipNext = false;

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 13) {
            skipNext = true;
        } else if (!skipNext) {
            sum += nums[i];
        }

        // Reset skipNext flag after a 13 or after the next number
        if (nums[i] != 13 || (i + 1 == nums.length)) {
            skipNext = false;
        }
    }

    return sum;
}

